const realtimeItems = $('Code in JavaScript').all().map(i => i.json);
const item = realtimeItems.reduce((max, i) => i.timestep > max.timestep ? i : max, realtimeItems[0]);

// ── Mode ──────────────────────────────────────────────────────────────────────
const mode = 'selfish';

// ── Real-time state — buses at current timestep ───────────────────────────────
const currentTimestep = item.timestep;
const realtimeState   = item.buses;

// ── Day-ahead reference ───────────────────────────────────────────────────────
const dayAheadRef     = $('Prepare Day-Ahead Reference').first().json;
const dayAheadSummary = dayAheadRef.summary;

// ── Re-optimization history from realtime plan ────────────────────────────────
const realtimePlanItems = $('Load day_ahead_plan').all().map(i => i.json);

const lastReopt = realtimePlanItems
  .filter(r => r.reoptimized === true && r.timestep <= currentTimestep)
  .sort((a, b) => b.timestep - a.timestep)[0] || null;

const lastReoptTimestep        = lastReopt?.timestep ?? null;
const lastReoptBuyMultipliers  = lastReopt?.buy_multipliers
  ? JSON.parse(lastReopt.buy_multipliers) : null;
const lastReoptSellMultipliers = lastReopt?.sell_multipliers
  ? JSON.parse(lastReopt.sell_multipliers) : null;
const lastReoptPrices          = lastReopt?.intraday_prices
  ? JSON.parse(lastReopt.intraday_prices) : null;
const lastReoptTriggerType     = lastReopt?.trigger_type ?? null;

const reoptPlanAtTimestep = realtimePlanItems.find(
  r => r.timestep === currentTimestep && r.reoptimized === true
) || null;

const plannedAtTimestep = reoptPlanAtTimestep
  ? {
      bus_1_kwh: reoptPlanAtTimestep.bus_1_kwh,
      bus_2_kwh: reoptPlanAtTimestep.bus_2_kwh,
      bus_3_kwh: reoptPlanAtTimestep.bus_3_kwh,
      bus_4_kwh: reoptPlanAtTimestep.bus_4_kwh,
      bus_5_kwh: reoptPlanAtTimestep.bus_5_kwh,
      bus_6_kwh: reoptPlanAtTimestep.bus_6_kwh,
      bus_7_kwh: reoptPlanAtTimestep.bus_7_kwh,
      bus_8_kwh: reoptPlanAtTimestep.bus_8_kwh,
    }
  : dayAheadRef.plan[currentTimestep] || null;

// ── Intraday prices ───────────────────────────────────────────────────────────
const disturbedPrices  = $('Price Disturbance node').first().json.prices;
const forecastedPrices = $('Load Forecasted Reality').all().map(i => i.json);
const allPrices        = $('Code in JavaScript1').first().json.prices;

const currentObservedPrice   = disturbedPrices.find(p => p.timestep === currentTimestep)?.spot_market ?? null;
const currentForecastedPrice = forecastedPrices.find(p => p.timestep === currentTimestep)?.spot_market ?? null;
const undisturbedPrice       = allPrices.find(p => p.timestep === currentTimestep)?.spot_market ?? null;

const priceDeviationPct = currentObservedPrice !== null && currentForecastedPrice !== null
  ? parseFloat(((currentObservedPrice - currentForecastedPrice) / currentForecastedPrice * 100).toFixed(2))
  : null;

const extendedPrices = disturbedPrices.filter(p => p.timestep >= currentTimestep);

const fullPriceMap = {};
for (const p of allPrices) {
  if (p.timestep < currentTimestep) fullPriceMap[p.timestep] = p.spot_market;
}
for (const p of disturbedPrices) {
  if (p.timestep >= currentTimestep) fullPriceMap[p.timestep] = p.spot_market;
}

const fullPrices = [];
for (let t = 1; t <= 48; t++) {
  fullPrices.push({ timestep: t, spot_market: fullPriceMap[t] ?? null });
}
const fullPricesComplete = fullPrices.every(p => p.spot_market !== null);

const avgRemainingPrice = extendedPrices.length > 0
  ? parseFloat((extendedPrices.reduce((a, b) => a + b.spot_market, 0) / extendedPrices.length).toFixed(6))
  : null;
const minRemainingPrice = extendedPrices.length > 0
  ? parseFloat(Math.min(...extendedPrices.map(p => p.spot_market)).toFixed(6))
  : null;
const maxRemainingPrice = extendedPrices.length > 0
  ? parseFloat(Math.max(...extendedPrices.map(p => p.spot_market)).toFixed(6))
  : null;

// ── Forecasted Energy Reality ─────────────────────────────────────────────────
const forecastedEnergyItems = $('Load Forecasted Energy').all().map(i => i.json);
const forecastedEnergyMap = {};
for (const row of forecastedEnergyItems) {
  forecastedEnergyMap[row.timestep] = row;
}

const disturbedDelta = $('Energy Disturbance node').first().json.disturbed_delta ?? {};
const delayInfo      = $('Delay node').first().json.delay_info ?? {};
const delayRemovalActive = $('Delay node').first().json.delay_removal_active ?? false;

// ── Deviations — energy-based ─────────────────────────────────────────────────
const deviations = realtimeState.map(bus => {
  const busKey = `bus_${bus.bus_id}_kwh`;

  const plannedKwh         = plannedAtTimestep ? (plannedAtTimestep[busKey] ?? null) : null;
  const energyDeviationKwh = plannedKwh !== null
    ? parseFloat((bus.current_energy_kwh - plannedKwh).toFixed(2)) : 0;
  const energyDeviationPct = plannedKwh !== null && plannedKwh > 0
    ? parseFloat(((bus.current_energy_kwh - plannedKwh) / plannedKwh * 100).toFixed(2)) : 0;

  const actualDelta     = disturbedDelta[busKey] ?? null;
  const forecastedCurr  = forecastedEnergyMap[currentTimestep]?.[busKey] ?? null;
  const forecastedPrev  = forecastedEnergyMap[currentTimestep - 1]?.[busKey] ?? null;
  const forecastedDelta = forecastedCurr !== null && forecastedPrev !== null
    ? forecastedCurr - forecastedPrev : null;

  const energyDeltaDeviationKwh = actualDelta !== null && forecastedDelta !== null
    ? parseFloat((actualDelta - forecastedDelta).toFixed(2)) : null;
  const energyDeltaDeviationPct = actualDelta !== null && forecastedDelta !== null && Math.abs(forecastedDelta) > 0.01
    ? parseFloat(((actualDelta - forecastedDelta) / Math.abs(forecastedDelta) * 100).toFixed(2)) : null;

  const delayMinutes = delayInfo[bus.bus_id] ?? 0;

  return {
    bus_id:                      bus.bus_id,
    current_energy_kwh:          bus.current_energy_kwh,
    planned_energy_kwh:          plannedKwh,
    energy_deviation_kwh:        energyDeviationKwh,
    energy_deviation_pct:        energyDeviationPct,
    actual_interval_delta_kwh:   actualDelta,
    forecast_interval_delta_kwh: forecastedDelta,
    energy_delta_deviation_kwh:  energyDeltaDeviationKwh,
    energy_delta_deviation_pct:  energyDeltaDeviationPct,
    delay_minutes:               delayMinutes,
    operation_status:            bus.operation_status,
    is_delayed:                  Math.abs(delayMinutes) > 0,
    is_in_trip:                  bus.operation_status === 'in_trip',
  };
});

// ── Deviation summary ─────────────────────────────────────────────────────────
const maxEnergyDeviationPct = Math.max(...deviations.map(d => Math.abs(d.energy_deviation_pct)));

const maxEnergyDeltaDeviationPct = Math.max(
  ...deviations.map(d => d.energy_delta_deviation_pct !== null ? Math.abs(d.energy_delta_deviation_pct) : 0)
);

const disturbedEnergyBuses = deviations.filter(
  d => d.energy_delta_deviation_pct !== null && Math.abs(d.energy_delta_deviation_pct) > 10
);

const delayedBuses = deviations.filter(d => Math.abs(d.delay_minutes) > 0);
const inTripBuses  = deviations.filter(d => d.is_in_trip);

const hasSevereDeviation   = maxEnergyDeviationPct > 10;
const hasEnergyDisturbance = disturbedEnergyBuses.length > 0;

// ── Historical state ──────────────────────────────────────────────────────────
const history = realtimeItems
  .filter(i => i.timestep < currentTimestep)
  .map(i => {
    const reoptAtT = realtimePlanItems.find(
      r => r.timestep === i.timestep && r.reoptimized === true
    ) || null;
    const plannedAtT = reoptAtT
      ? {
          bus_1_kwh: reoptAtT.bus_1_kwh,
          bus_2_kwh: reoptAtT.bus_2_kwh,
          bus_3_kwh: reoptAtT.bus_3_kwh,
          bus_4_kwh: reoptAtT.bus_4_kwh,
          bus_5_kwh: reoptAtT.bus_5_kwh,
          bus_6_kwh: reoptAtT.bus_6_kwh,
          bus_7_kwh: reoptAtT.bus_7_kwh,
          bus_8_kwh: reoptAtT.bus_8_kwh,
        }
      : dayAheadRef.plan[i.timestep] || null;

    return {
      timestep:    i.timestep,
      reoptimized: reoptAtT !== null,
      buses: i.buses.map(bus => {
        const busKey             = `bus_${bus.bus_id}_kwh`;
        const plannedKwh         = plannedAtT ? (plannedAtT[busKey] ?? null) : null;
        const energyDeviationKwh = plannedKwh !== null
          ? parseFloat((bus.current_energy_kwh - plannedKwh).toFixed(2)) : null;
        const energyDeviationPct = plannedKwh !== null && plannedKwh > 0
          ? parseFloat(((bus.current_energy_kwh - plannedKwh) / plannedKwh * 100).toFixed(2)) : null;
        return {
          bus_id:               bus.bus_id,
          current_energy_kwh:   bus.current_energy_kwh,
          planned_energy_kwh:   plannedKwh,
          energy_deviation_kwh: energyDeviationKwh,
          energy_deviation_pct: energyDeviationPct,
          operation_status:     bus.operation_status,
          delay_minutes:        bus.delay_minutes ?? 0, // ← from realtimeItems, not current delayInfo
        };
      }),
    };
  });

// ── Pre-computed trigger flags ────────────────────────────────────────────────
const DELAY_THRESHOLD_MIN       = 15;
const ENERGY_DEV_THRESHOLD_HIGH = 10;
const ENERGY_DEV_THRESHOLD_LOW  = 5;
const PRICE_DEV_THRESHOLD       = 15;

const busesWithSevereDelay = deviations.filter(
  d => Math.abs(d.delay_minutes) >= DELAY_THRESHOLD_MIN
);
const busesWithHighEnergyDev = deviations.filter(
  d => d.energy_deviation_pct !== null && Math.abs(d.energy_deviation_pct) > ENERGY_DEV_THRESHOLD_HIGH
);
const busesWithModerateEnergyDev = deviations.filter(
  d => d.energy_deviation_pct !== null && Math.abs(d.energy_deviation_pct) > ENERGY_DEV_THRESHOLD_LOW
);

// ── Delay sign change detection ───────────────────────────────────────────────
const delaySignReversedBuses = [];

if (
  !delayRemovalActive &&
  lastReoptTimestep !== null &&
  lastReoptTriggerType === 'operational'
) {
  const historyAtLastReopt = history.find(h => h.timestep === lastReoptTimestep);
  if (historyAtLastReopt) {
    for (const currentDev of busesWithSevereDelay) {
      const histBus = historyAtLastReopt.buses.find(b => b.bus_id === currentDev.bus_id);
      if (histBus) {
        const lastDelay    = histBus.delay_minutes ?? 0;
        const currentDelay = currentDev.delay_minutes ?? 0;
        const signReversed =
          Math.abs(lastDelay) >= DELAY_THRESHOLD_MIN &&
          Math.abs(currentDelay) >= DELAY_THRESHOLD_MIN &&
          Math.sign(lastDelay) !== Math.sign(currentDelay);
        if (signReversed) {
          delaySignReversedBuses.push({
            bus_id:              currentDev.bus_id,
            delay_at_last_reopt: lastDelay,
            delay_now:           currentDelay,
          });
        }
      }
    }
  }
}

const trigger_flags = {
  has_severe_delay:             busesWithSevereDelay.length > 0,
  severe_delay_buses:           busesWithSevereDelay.map(d => ({ bus_id: d.bus_id, delay_minutes: d.delay_minutes })),
  has_high_energy_deviation:    busesWithHighEnergyDev.length > 0,
  high_energy_deviation_buses:  busesWithHighEnergyDev.map(d => ({ bus_id: d.bus_id, energy_deviation_pct: d.energy_deviation_pct })),
  multi_bus_moderate_deviation: busesWithModerateEnergyDev.length >= 2,
  moderate_deviation_buses:     busesWithModerateEnergyDev.map(d => ({ bus_id: d.bus_id, energy_deviation_pct: d.energy_deviation_pct })),
  price_high:                   priceDeviationPct !== null && priceDeviationPct > PRICE_DEV_THRESHOLD,
  price_low:                    priceDeviationPct !== null && priceDeviationPct < -PRICE_DEV_THRESHOLD,
  price_deviation_significant:  priceDeviationPct !== null && Math.abs(priceDeviationPct) > PRICE_DEV_THRESHOLD,
  unexpected_discharging_buses: realtimeState
    .filter(b => b.operation_status === 'discharging')
    .map(b => b.bus_id),
  delay_sign_reversed:          delaySignReversedBuses.length > 0,
  delay_sign_reversed_buses:    delaySignReversedBuses,
  delay_removal_active:         delayRemovalActive,
};

// ── Remaining horizon ─────────────────────────────────────────────────────────
const totalTimesteps     = 48;
const remainingTimesteps = totalTimesteps - currentTimestep + 1;
const remainingHours     = ((remainingTimesteps * 30) / 60).toFixed(1);

// ── Dynamic periods from day-ahead summary ────────────────────────────────────
const daBuyMults  = dayAheadSummary.buy_multipliers  || [1.05, 1.10, 1.05];
const daSellMults = dayAheadSummary.sell_multipliers || [0.80, 0.85, 0.80];
const nPeriods    = daBuyMults.length;
const periodSize  = Math.floor(48 / nPeriods);

function getDAPeriod(t) {
  for (let p = 0; p < nPeriods - 1; p++) {
    if (t <= (p + 1) * periodSize) return p;
  }
  return nPeriods - 1;
}

// ── Day-ahead benchmark ───────────────────────────────────────────────────────
let da_revenue_remaining = 0;
let da_cost_remaining    = 0;
let da_benchmark_valid   = true;

if (fullPricesComplete && fullPrices.length === 48 && dayAheadRef.plan.length === 48) {
  for (let t = currentTimestep; t <= 48; t++) {
    const i      = t - 1;
    const price  = fullPrices[i]?.spot_market ?? null;
    const row    = dayAheadRef.plan[t] || null;
    const w_buy  = row?.w_buy  ?? null;
    const w_sell = row?.w_sell ?? null;

    if (price === null || w_buy === null || w_sell === null) {
      da_benchmark_valid = false;
      break;
    }

    const period = getDAPeriod(t);
    const s_buy  = daBuyMults[period]  * price;
    const s_sell = daSellMults[period] * price;

    da_revenue_remaining += (s_buy  - price)  * w_buy
                          + (price  - s_sell)  * w_sell;
    da_cost_remaining    +=  s_buy  * w_buy
                          -  s_sell * w_sell;
  }
} else {
  da_benchmark_valid = false;
}

da_revenue_remaining = parseFloat(da_revenue_remaining.toFixed(4));
da_cost_remaining    = parseFloat(da_cost_remaining.toFixed(4));

// ── Final context ─────────────────────────────────────────────────────────────
const context = {
  timestep:            currentTimestep,
  total_timesteps:     totalTimesteps,
  remaining_timesteps: remainingTimesteps,
  remaining_hours:     remainingHours,
  mode,
  trigger_flags,
  n_periods:           nPeriods,
  period_size:         periodSize,

  realtime_state: realtimeState.map(bus => ({
    bus_id:             bus.bus_id,
    current_energy_kwh: bus.current_energy_kwh,
    operation_status:   bus.operation_status,
    delay_minutes:      delayInfo[bus.bus_id] ?? 0,
  })),

  day_ahead_state: deviations.map(d => ({
    bus_id:             d.bus_id,
    planned_energy_kwh: d.planned_energy_kwh,
  })),

  day_ahead_summary: {
    pto_daily_cost:     dayAheadSummary.pto_daily_cost,
    aggregator_revenue: dayAheadSummary.aggregator_revenue,
    buy_multipliers:    dayAheadSummary.buy_multipliers,
    sell_multipliers:   dayAheadSummary.sell_multipliers,
    avg_grid_price:     dayAheadSummary.avg_grid_price,
  },

  reoptimization_history: {
    last_reopt_timestep:         lastReoptTimestep,
    last_reopt_trigger_type:     lastReoptTriggerType,
    last_reopt_buy_multipliers:  lastReoptBuyMultipliers,
    last_reopt_sell_multipliers: lastReoptSellMultipliers,
    last_reopt_prices:           lastReoptPrices,
    using_reopt_plan:            reoptPlanAtTimestep !== null,
  },

  da_benchmark: {
    da_revenue_remaining,
    da_cost_remaining,
    da_remaining_steps: remainingTimesteps,
    da_benchmark_valid,
  },

  intraday_prices: {
    remaining_count:     extendedPrices.length,
    avg_price:           avgRemainingPrice,
    min_price:           minRemainingPrice,
    max_price:           maxRemainingPrice,
    current_price:       currentObservedPrice,
    forecasted_price:    currentForecastedPrice,
    undisturbed_price:   undisturbedPrice,
    price_deviation_pct: priceDeviationPct,
    prices:              extendedPrices,
  },

  deviations,

  deviation_summary: {
    max_energy_deviation_pct:       maxEnergyDeviationPct,
    has_severe_deviation:           hasSevereDeviation,
    max_energy_delta_deviation_pct: maxEnergyDeltaDeviationPct,
    has_energy_disturbance:         hasEnergyDisturbance,
    disturbed_energy_buses:         disturbedEnergyBuses.map(d => d.bus_id),
    disturbed_energy_bus_count:     disturbedEnergyBuses.length,
    delayed_buses:                  delayedBuses.map(d => d.bus_id),
    delayed_bus_count:              delayedBuses.length,
    in_trip_bus_count:              inTripBuses.length,
    has_delays:                     delayedBuses.length > 0,
  },

  history,
};

return [{ json: { context } }];

const planRows = $('Load day_ahead_plan').all().map(i => i.json);
const summary  = $('Load day_ahead_summary').all()
  .map(i => i.json)
  .find(r => r.mode === 'selfish');

// Build lookup: timestep → plan data
const plan = {};
for (const row of planRows) {
  plan[row.timestep] = {
    w_buy:     parseFloat(row.w_buy)     || 0,
    w_sell:    parseFloat(row.w_sell)    || 0,
    bus_1_kwh: parseFloat(row.bus_1_kwh) || null,
    bus_2_kwh: parseFloat(row.bus_2_kwh) || null,
    bus_3_kwh: parseFloat(row.bus_3_kwh) || null,
    bus_4_kwh: parseFloat(row.bus_4_kwh) || null,
    bus_5_kwh: parseFloat(row.bus_5_kwh) || null,
    bus_6_kwh: parseFloat(row.bus_6_kwh) || null,
    bus_7_kwh: parseFloat(row.bus_7_kwh) || null,
    bus_8_kwh: parseFloat(row.bus_8_kwh) || null,
  };
}

return [{
  json: {
    plan,
    summary: {
      mode:               summary.mode               || 'selfish',
      pto_daily_cost:     parseFloat(summary.pto_daily_cost)     || null,
      aggregator_revenue: parseFloat(summary.aggregator_revenue) || null,
      buy_multipliers:    JSON.parse(summary.buy_multipliers),
      sell_multipliers:   JSON.parse(summary.sell_multipliers),
      avg_grid_price:     parseFloat(summary.avg_grid_price)     || null,
    }
  }
}];

const rows = $('Load Prices').all().map(i => i.json);
const currentTimestep = $('Timestep').first().json.targetTimestep;

// Only keep rows that have spot_market (price rows, not scenario rows)
const filteredPrices = rows
  .filter(r => r.spot_market !== undefined && r.timestep <= currentTimestep)
  .sort((a, b) => a.timestep - b.timestep)
  .map(r => ({ timestep: r.timestep, spot_market: r.spot_market }));

return [{
  json: {
    start_timestep: 1,
    prices: filteredPrices,
  }
}];

parameters.text:
=## CURRENT MODE: {{ $('Prepare Day-Ahead Reference').last().json.summary.mode }}

---
## OPTIMIZATION RESULT
- is_mock: {{ $('Extract Result').last().json.is_mock }}
- solver_status: {{ $('Extract Result').last().json.solver_status ?? 'unknown' }}
- infeasible: {{ $('Extract Result').last().json.is_mock === true && ($('Extract Result').last().json.solver_status === 'infeasible' || $('Extract Result').last().json.solver_status === 'unknown') ? 'true' : 'false' }}
- pto_daily_cost: {{ $('Extract Result').last().json.pto_daily_cost }}
- aggregator_revenue: {{ $('Extract Result').last().json.aggregator_revenue }}
- total_kwh_bought: {{ $('Extract Result').last().json.total_kwh_bought }}
- total_kwh_sold: {{ $('Extract Result').last().json.total_kwh_sold }}
- avg_buy_price: {{ $('Extract Result').last().json.avg_buy_price }}
- avg_sell_price: {{ $('Extract Result').last().json.avg_sell_price }}
- buy_multipliers (per timestep): {{ JSON.stringify($('Extract Result').last().json.buy_multipliers) }}
- sell_multipliers (per timestep): {{ JSON.stringify($('Extract Result').last().json.sell_multipliers) }}

---
## DAY-AHEAD BASELINE
- pto_daily_cost: {{ $('Prepare Day-Ahead Reference').last().json.summary.pto_daily_cost }}
- aggregator_revenue: {{ $('Prepare Day-Ahead Reference').last().json.summary.aggregator_revenue }}
- avg_grid_price: {{ $('Prepare Day-Ahead Reference').last().json.summary.avg_grid_price }}
- buy_multipliers (per timestep): {{ JSON.stringify($('Prepare Day-Ahead Reference').last().json.summary.buy_multipliers) }}
- sell_multipliers (per timestep): {{ JSON.stringify($('Prepare Day-Ahead Reference').last().json.summary.sell_multipliers) }}

## DAY-AHEAD BENCHMARK (REMAINING HORIZON)
- da_revenue_remaining: {{ $('Build LLM context').last().json.context.da_benchmark.da_revenue_remaining }}
- da_cost_remaining: {{ $('Build LLM context').last().json.context.da_benchmark.da_cost_remaining }}
- da_remaining_steps: {{ $('Build LLM context').last().json.context.da_benchmark.da_remaining_steps }}
- da_benchmark_valid: {{ $('Build LLM context').last().json.context.da_benchmark.da_benchmark_valid }}

These values represent what the day-ahead plan projected for the SAME remaining
horizon as the current optimization result. Use these for comparison instead of
the full-day baseline figures. If da_benchmark_valid=false, fall back to
per-step efficiency comparison.

---
## FLEET CONTEXT
- remaining_timesteps: {{ $('Build LLM context').last().json.context.remaining_timesteps }}
- current_timestep: {{ $('Build LLM context').last().json.context.timestep }}
- max_energy_deviation_pct: {{ $('Build LLM context').last().json.context.deviation_summary.max_energy_deviation_pct }}
- trigger_type: {{ $('Trigger Agent').last().json.output.trigger_type }}
- flagged_buses: {{ JSON.stringify($('Trigger Agent').last().json.output.flagged_buses) }}
- deviations: {{ JSON.stringify($('Build LLM context').last().json.context.deviations.map(d => ({ bus_id: d.bus_id, energy_deviation_pct: d.energy_deviation_pct }))) }}
- current_price: {{ $('Build LLM context').last().json.context.intraday_prices.current_price }}
- forecasted_price: {{ $('Build LLM context').last().json.context.intraday_prices.forecasted_price }}
- price_deviation_pct: {{ $('Build LLM context').last().json.context.intraday_prices.price_deviation_pct }}
- last_reopt_timestep: {{ $('Build LLM context').last().json.context.reoptimization_history.last_reopt_timestep }}
- using_reopt_plan: {{ $('Build LLM context').last().json.context.reoptimization_history.using_reopt_plan }}
- optimized_steps: {{ $('Build LLM context').last().json.context.remaining_timesteps }}

---
## END-OF-DAY BUS ENERGY
Per-bus projected energy at end of optimization horizon (used for STEP 4B check):
{{ (() => {
  const energy = $('Update Best State').first().json.best_energy;
  const currentTimestep = $('Build LLM context').last().json.context.timestep;
  if (!energy || !Array.isArray(energy)) return 'not available';
  return JSON.stringify(energy.map((busEnergy, idx) => ({
    bus_id: idx + 1,
    end_of_day_energy_kwh: Array.isArray(busEnergy) ? (busEnergy[busEnergy.length - 1] ?? null) : null,
    end_of_day_timestep: Array.isArray(busEnergy) ? (currentTimestep + busEnergy.length - 1) : null
  })));
})() }}

Threshold for STEP 4B: end_of_day_energy_kwh > 173 kWh = surplus V2G opportunity missed.
173 kWh = 20% minimum SOC (73 kWh) + one full charge cycle (100 kWh).

---
## TRIP SCHEDULE (for V2G timing guidance in STEP 4B feedback)
{{ JSON.stringify($('Assembler node').first().json.input.trip_time.map(t => ({
  bus_id: t.bus_id,
  trip_end_time: t.time_end,
  trip_end_timestep: (() => {
    const [h, m] = t.time_end.split(':').map(Number);
    return Math.floor((h * 60 + m) / 30) + 1;
  })()
}))) }}

Use trip_end_timestep to determine when each bus returns and becomes available
for V2G dispatch. When a bus has end_of_day_energy_kwh > 173, raise sell
multipliers starting from that bus's trip_end_timestep.

