const result = $('Poll Job Result').first().json;

let rerun_count = 0;
try {
  rerun_count = $('Check Rerun Cap').first().json.rerun_count ?? 0;
} catch(e) {}

return [{
  json: {
    status:                  result.status,
    is_mock:                 result.is_mock,
    mock_reason:             result.mock_reason ?? null,
    // Price settings
    buy_multipliers:         result.buy_multipliers,
