    avg_grid_price:          result.avg_grid_price,
    avg_buy_price:           result.avg_buy_price,
    avg_sell_price:          result.avg_sell_price,
    price_guidance_used:     result.price_guidance_used,
    // Economic outcomes
    pto_daily_cost:          result.pto_daily_cost,
    aggregator_revenue:      result.aggregator_revenue,
    aggregator_buy_margin:   result.aggregator_buy_margin,
    aggregator_sell_margin:  result.aggregator_sell_margin,
    total_buy_cost:          result.total_buy_cost,
    total_sell_revenue:      result.total_sell_revenue,
    total_degradation:       result.total_degradation ?? null,
    total_kwh_sold:          result.total_kwh_sold,
    total_kwh_bought:        result.total_kwh_bought,
    // Time series
    w_buy:                   result.w_buy,
    w_sell:                  result.w_sell,
    energy:                  result.energy,
    // Pass-through
    rerun_count:             rerun_count,
    disturbances_applied:    [],
  }
}];

const result = $('Extract Result').first().json;

let mode = 'selfish';
try {
  mode = $('Build LLM context').first().json.context.mode || 'selfish';
} catch(e) { mode = 'selfish'; }

// Selfish:    maximize aggregator_revenue
// Altruistic: minimize pto_daily_cost (negate so higher = better for comparison)
const aggregator_profit = mode === 'selfish'
  ? (result.aggregator_revenue ?? 0)
  : -(result.pto_daily_cost ?? 0);

return [{
  json: {
    ...result,
    aggregator_profit: aggregator_profit,
    mode: mode,
  }
}];

let metrics = {};
try { metrics = $('Compute Metrics').first().json; } catch(e) {
  try { metrics = $('Extract Result').first().json; } catch(e2) {}
}

// Detect new timestep — reset best state if Check Rerun Cap wasn't executed
// (first run at a new timestep) or if timestep changed
const currentTimestep = $('Build LLM context').first().json.context.timestep;
let prev_timestep = null;
try {
  prev_timestep = $('Check Rerun Cap').isExecuted
    ? $('Check Rerun Cap').last().json.timestep ?? null
    : null;
} catch(e) {}

const isNewTimestep = prev_timestep !== currentTimestep;

let prev = {};
try { prev = $('Check Rerun Cap').first().json; } catch(e) {}

const current_mode = metrics.mode ||
                     $('Build LLM context').first().json.context.mode ||
                     'altruistic';

const remainingTimesteps = $('Build LLM context').first().json.context.remaining_timesteps || 48;

const current_best_selfish    = isNewTimestep ? -Infinity : (parseFloat(prev.best_selfish_revenue) || -Infinity);
const current_best_altruistic = isNewTimestep ?  Infinity : (parseFloat(prev.best_altruistic_cost) ||  Infinity);

let best_selfish_revenue = isFinite(current_best_selfish)    ? current_best_selfish    : -Infinity;
let best_altruistic_cost = isFinite(current_best_altruistic) ? current_best_altruistic :  Infinity;

let best_buy_mults  = isNewTimestep ? null : (prev.best_buy_multipliers  ?? null);
let best_sell_mults = isNewTimestep ? null : (prev.best_sell_multipliers ?? null);
if (typeof best_buy_mults  === 'string') try { best_buy_mults  = JSON.parse(best_buy_mults);  } catch(e) {}
if (typeof best_sell_mults === 'string') try { best_sell_mults = JSON.parse(best_sell_mults); } catch(e) {}

let best_w_buy  = isNewTimestep ? null : (prev.best_w_buy  ?? null);
let best_w_sell = isNewTimestep ? null : (prev.best_w_sell ?? null);
let best_energy = isNewTimestep ? null : (prev.best_energy ?? null);
if (typeof best_w_buy  === 'string') try { best_w_buy  = JSON.parse(best_w_buy);  } catch(e) {}
if (typeof best_w_sell === 'string') try { best_w_sell = JSON.parse(best_w_sell); } catch(e) {}
if (typeof best_energy === 'string') try { best_energy = JSON.parse(best_energy); } catch(e) {}

let best_mode   = isNewTimestep ? current_mode : (prev.best_mode ?? current_mode);
let is_new_best = false;

// Default fallbacks — per-timestep arrays
const defaultBuyMults  = Array(remainingTimesteps).fill(1.20);
const defaultSellMults = Array(remainingTimesteps).fill(0.55);
const defaultBuyAlt    = Array(remainingTimesteps).fill(1.03);
const defaultSellAlt   = Array(remainingTimesteps).fill(0.90);

if (!metrics.is_mock) {
  if (current_mode === 'selfish' &&
      metrics.aggregator_revenue !== null &&
      metrics.aggregator_revenue !== undefined &&
      isFinite(parseFloat(metrics.aggregator_revenue)) &&
      parseFloat(metrics.aggregator_revenue) > best_selfish_revenue) {
    best_selfish_revenue = parseFloat(metrics.aggregator_revenue);
    best_buy_mults       = metrics.buy_multipliers  || defaultBuyMults;
    best_sell_mults      = metrics.sell_multipliers || defaultSellMults;
    best_mode            = 'selfish';
    best_w_buy           = metrics.w_buy   ?? null;
    best_w_sell          = metrics.w_sell  ?? null;
    best_energy          = metrics.energy  ?? null;
    is_new_best          = true;
  }
  if (current_mode === 'altruistic' &&
      metrics.pto_daily_cost !== null &&
      metrics.pto_daily_cost !== undefined &&
      isFinite(parseFloat(metrics.pto_daily_cost)) &&
      parseFloat(metrics.pto_daily_cost) < best_altruistic_cost) {
    best_altruistic_cost = parseFloat(metrics.pto_daily_cost);
    best_buy_mults       = metrics.buy_multipliers  || defaultBuyAlt;
    best_sell_mults      = metrics.sell_multipliers || defaultSellAlt;
    best_mode            = 'altruistic';
    best_w_buy           = metrics.w_buy   ?? null;
    best_w_sell          = metrics.w_sell  ?? null;
    best_energy          = metrics.energy  ?? null;
    is_new_best          = true;
  }
}

return [{
  json: {
    ...metrics,
    best_selfish_revenue,
    best_altruistic_cost,
    best_buy_multipliers:  best_buy_mults,
    best_sell_multipliers: best_sell_mults,
    best_mode,
    is_new_best,
    best_w_buy,
    best_w_sell,
    best_energy,
  }
}];

const assemblerInput    = $('Assembler node').first().json.input;
const disturbedPrices   = $('Price Disturbance node').first().json.prices;
const disturbedEnergy   = $('Energy Disturbance node').first().json.energy_consumption;
const disturbedTripTime = $('Delay node').first().json.trip_time;
const scenarios         = $('Filter2').all().map(i => i.json);
const context           = $('Build LLM context').first().json.context;

// Get LLM 2 multipliers
const llm2Raw    = $('Structurer3').first().json;
const llm2Output = llm2Raw.output ?? llm2Raw;

// Get rerun count
let rerunCount = 0;
try {
  rerunCount = $('Check Rerun Cap').first().json.rerun_count ?? 0;
} catch(e) {}

// Validate multiplier arrays — per-timestep, no period_boundaries
const remainingTimesteps = context.remaining_timesteps;
const buyMultipliers = Array.isArray(llm2Output.buy_multipliers) && llm2Output.buy_multipliers.length > 0
  ? llm2Output.buy_multipliers
  : Array(remainingTimesteps).fill(1.05);
const sellMultipliers = Array.isArray(llm2Output.sell_multipliers) && llm2Output.sell_multipliers.length > 0
  ? llm2Output.sell_multipliers
  : Array(remainingTimesteps).fill(0.80);

// Build price guidance
const priceGuidance = {
  buy_multipliers:  buyMultipliers,
  sell_multipliers: sellMultipliers,
  mode:             context.mode || 'altruistic',
};

// Delay disturbances — collect all active delay scenarios
const disturbances = scenarios
  .filter(s => s.scenario_id?.startsWith('delay_'))
  .map(s => ({
    bus_id:           s.target_bus_id,
    delay_minutes:    s.scenario_level * s.disturbance_sign,
    disturbance_type: s.disturbance_sign > 0 ? 'late' : 'early_return',
  }));

// Build final input — trip_time from Delay node overrides assemblerInput.trip_time
const finalInput = {
  ...assemblerInput,
  prices:             disturbedPrices,
  energy_consumption: disturbedEnergy,
  trip_time:          disturbedTripTime,
  disturbance:        scenarios,
};

// Logging
console.log('LLM2 raw output:', JSON.stringify(llm2Raw));
console.log('Price guidance:', JSON.stringify(priceGuidance));
console.log('Disturbances:', JSON.stringify(disturbances));
console.log('optimization_mode: real_time');
console.log('current_timestep:', context.timestep);
console.log('remaining_timesteps:', remainingTimesteps);
console.log('buy_multipliers length:', buyMultipliers.length);
console.log('rerun_count:', rerunCount);

return [{
  json: {
    input:             finalInput,
    optimization_mode: 'real_time',
    current_timestep:  context.timestep,
    price_guidance:    priceGuidance,
    disturbances:      disturbances,
    rerun_count:       rerunCount,
    v2g_enabled:       true,
  }
}];

const raw = $input.first().json;
const result = raw.output ?? raw;
const MAX_RERUNS = 5;
const currentTimestep = $('Build LLM context').last().json.context.timestep;

let prev_rerun_count = 0;
let prev_timestep    = null;
try {
  prev_rerun_count = $('Check Rerun Cap').last().json.rerun_count ?? 0;
  prev_timestep    = $('Check Rerun Cap').last().json.timestep    ?? null;
} catch(e) {}

const rerun_count    = (prev_timestep === currentTimestep)
  ? prev_rerun_count + 1
  : 1;
const isNewTimestep  = prev_timestep !== currentTimestep;

let best_buy  = isNewTimestep ? null : ($('Update Best State').first().json.best_buy_multipliers  ?? null);
let best_sell = isNewTimestep ? null : ($('Update Best State').first().json.best_sell_multipliers ?? null);
if (typeof best_buy  === 'string') try { best_buy  = JSON.parse(best_buy);  } catch(e) {}
if (typeof best_sell === 'string') try { best_sell = JSON.parse(best_sell); } catch(e) {}

let best_w_buy  = isNewTimestep ? null : ($('Update Best State').first().json.best_w_buy  ?? null);
let best_w_sell = isNewTimestep ? null : ($('Update Best State').first().json.best_w_sell ?? null);
let best_energy = isNewTimestep ? null : ($('Update Best State').first().json.best_energy ?? null);
if (typeof best_w_buy  === 'string') try { best_w_buy  = JSON.parse(best_w_buy);  } catch(e) {}
if (typeof best_w_sell === 'string') try { best_w_sell = JSON.parse(best_w_sell); } catch(e) {}
if (typeof best_energy === 'string') try { best_energy = JSON.parse(best_energy); } catch(e) {}

const best_state = {
  best_selfish_revenue:  isNewTimestep ? -Infinity : ($('Update Best State').first().json.best_selfish_revenue  ?? -Infinity),
  best_altruistic_cost:  isNewTimestep ?  Infinity : ($('Update Best State').first().json.best_altruistic_cost  ??  Infinity),
  best_buy_multipliers:  best_buy,
  best_sell_multipliers: best_sell,
  best_mode:             isNewTimestep ? null : ($('Update Best State').first().json.best_mode ?? null),
  best_w_buy,
  best_w_sell,
  best_energy,
};

if (rerun_count >= MAX_RERUNS) {
  return [{
    json: {
      outcome:    'accept',
      reasoning:  `Rerun cap of ${MAX_RERUNS} reached. Accepting best result found.`,
      rerun_count,
      timestep:   currentTimestep,
      feedback:   null,
      ...best_state,
    }
  }];
}

return [{
  json: {
    outcome:    result.accept === true ? 'accept' : 'rerun',
    reasoning:  result.reasoning ?? null,
    rerun_count,
    timestep:   currentTimestep,
    feedback:   result.feedback  ?? null,
    ...best_state,
  }
}];

const context = $('Build LLM context').last().json.context;

// LLM 1 output
let llm1 = {};
try { llm1 = $('Trigger Agent').last().json.output ?? {}; } catch(e) {}


// LLM 2 output — read from Merge node (whichever Pricing Agent ran)
let llm2 = {};
try {
  const merge = $('Pricing Agent Selfish').last().json;
  llm2 = merge.output ?? merge ?? {};
} catch(e) {}

// LLM 3 output — check Evaluator Agent or skip node
let llm3 = {};
try {
  if ($('Evaluator Agent').isExecuted) {
    const ev = $('Evaluator Agent').last().json;
    llm3 = ev.output ?? ev ?? {};
  }
} catch(e) {}

// Check if Evaluator was skipped due to rerun cap
let accepted = llm3.accept ?? null;
try {
  if ($('Code in JavaScript3').isExecuted) {
    const skipNode = $('Code in JavaScript3').last().json;
    if (skipNode.skip_evaluator === true) {
      accepted = true;
    }
  }
} catch(e) {}

// Best result — read directly from Update Best State
let bestState = {};
try {
  if ($('Update Best State').isExecuted) {
    const upd = $('Update Best State').last().json;
    bestState = {
      best_w_buy:            upd.best_w_buy            ?? null,
      best_w_sell:           upd.best_w_sell           ?? null,
      best_energy:           upd.best_energy           ?? null,
      best_buy_multipliers:  upd.best_buy_multipliers  ?? null,
      best_sell_multipliers: upd.best_sell_multipliers ?? null,
      best_selfish_revenue:  upd.best_selfish_revenue  ?? null,
      best_altruistic_cost:  upd.best_altruistic_cost  ?? null,
      is_new_best:           upd.is_new_best           ?? null,
      pto_daily_cost:        upd.pto_daily_cost        ?? null,
      aggregator_revenue:    upd.aggregator_revenue    ?? null,
      total_kwh_bought:      upd.total_kwh_bought      ?? null,
      total_kwh_sold:        upd.total_kwh_sold        ?? null,
      avg_grid_price:        upd.avg_grid_price        ?? null,
      is_mock:               upd.is_mock               ?? null,
    };
  }
} catch(e) {}

// Rerun count
let rerunCount = 0;
try {
  rerunCount = $('Check Rerun Cap').isExecuted
    ? $('Check Rerun Cap').last().json.rerun_count ?? 0
    : 0;
} catch(e) {}

const action = llm1.action ?? 'skip';

// Economics — prefer best state values
const economics = {
  pto_daily_cost:     bestState.pto_daily_cost     ?? null,
  aggregator_revenue: bestState.aggregator_revenue ?? null,
  total_kwh_bought:   bestState.total_kwh_bought   ?? null,
  total_kwh_sold:     bestState.total_kwh_sold     ?? null,
  avg_grid_price:     bestState.avg_grid_price     ?? null,
  is_mock:            bestState.is_mock            ?? null,
};

// Multipliers — what LLM 2 proposed vs what was best
const proposedBuyMultipliers  = llm2.buy_multipliers  ?? null;
const proposedSellMultipliers = llm2.sell_multipliers ?? null;
const bestBuyMultipliers      = bestState.best_buy_multipliers  ?? null;
const bestSellMultipliers     = bestState.best_sell_multipliers ?? null;

// Intraday prices — use disturbed prices from Price Disturbance node
let intraday_prices = [];
let intraday_price  = null;
try {
  intraday_prices = $('Price Disturbance node').first().json.prices || [];
  const currentPrice = intraday_prices.find(p => p.timestep === context.timestep);
  intraday_price = currentPrice?.spot_market ?? null;
} catch(e) {}

// Actual buy/sell prices at current timestep — per-timestep multipliers
let buy_price  = null;
let sell_price = null;
try {
  if (intraday_price !== null && Array.isArray(llm2.buy_multipliers) && Array.isArray(llm2.sell_multipliers)) {
    // First value in array = current timestep
    buy_price  = intraday_price * llm2.buy_multipliers[0];
    sell_price = intraday_price * llm2.sell_multipliers[0];
  }
} catch(e) {}

// Build realtime_plan rows using BEST plan arrays from Update Best State
const realtime_plan = [];
if (
  action === 'optimize' &&
  bestState.best_w_buy  &&
  bestState.best_w_sell &&
  bestState.best_energy
) {
  const currentTimestep = context.timestep;
  const wBuy   = bestState.best_w_buy;
  const wSell  = bestState.best_w_sell;
  const energy = bestState.best_energy;

  for (let i = 0; i < wBuy.length; i++) {
    const t = currentTimestep + i;
    const row = {
      timestep:         t,
      w_buy:            wBuy[i]  ?? null,
      w_sell:           wSell[i] ?? null,
      reoptimized:      t === currentTimestep ? true : false,
      buy_multipliers:  t === currentTimestep ? JSON.stringify(bestBuyMultipliers) : null,
      sell_multipliers: t === currentTimestep ? JSON.stringify(bestSellMultipliers) : null,
      intraday_prices:  t === currentTimestep ? JSON.stringify(intraday_prices) : null,
    };
    for (let b = 0; b < 8; b++) {
      row[`bus_${b + 1}_kwh`] = energy?.[b]?.[i] ?? null;
    }
    realtime_plan.push(row);
  }
}

return [{
  json: {
    // Meta
    timestamp:               new Date().toISOString(),
    timestep:                context.timestep,
