    // LLM 1
    action,
    trigger_type:            llm1.trigger_type  ?? 'none',
    flagged_buses:           JSON.stringify(llm1.flagged_buses ?? []),
    llm1_reasoning:          llm1.reasoning     ?? null,
    llm1_confidence:         llm1.confidence    ?? null,
    // LLM 2 — proposed vs best
    buy_multipliers:         JSON.stringify(proposedBuyMultipliers),
    sell_multipliers:        JSON.stringify(proposedSellMultipliers),
    llm2_reasoning:          llm2.reasoning     ?? null,
    best_buy_multipliers:    JSON.stringify(bestBuyMultipliers),
    best_sell_multipliers:   JSON.stringify(bestSellMultipliers),
    is_new_best:             bestState.is_new_best ?? null,
    // LLM 3
    accept:                  accepted,
    rerun_count:             rerunCount,
    llm3_reasoning:          llm3.reasoning     ?? null,
    // Optimization result — from best state
    pto_daily_cost:          economics.pto_daily_cost,
    aggregator_revenue:      economics.aggregator_revenue,
    total_kwh_bought:        economics.total_kwh_bought,
    total_kwh_sold:          economics.total_kwh_sold,
    w_buy:  bestState.best_w_buy  ?? null,
    w_sell: bestState.best_w_sell ?? null,
    avg_grid_price:          economics.avg_grid_price,
    max_energy_deviation_pct: context.deviation_summary?.max_energy_deviation_pct ?? null,
    is_mock:                 economics.is_mock,
    // Realtime plan — built from Update Best State
    realtime_plan,
    // Prices
    intraday_price:          intraday_price,
    intraday_prices:         JSON.stringify(intraday_prices),
    buy_price:               buy_price,
    sell_price:              sell_price,
  }
}];

const allBuses      = $('Buses').all().map(i => i.json);
const allChargers   = $('Chargers').all().map(i => i.json);
const allTrips      = $('Trips').all().map(i => i.json);
const allPrices     = $('Code in JavaScript1').first().json.prices;
const scenarios     = $('Filter2').all().map(i => i.json);

const targetTimestep = allBuses.length / 8;
const offset8        = (targetTimestep - 1) * 8;

const buses = allBuses.slice(offset8, offset8 + 8).map(b => ({
  bus_id:      b.bus_id,
  bus_kwh:     b.bus_kwh,
  initial_soc: b.initial_soc,
}));

const chargers = allChargers.slice(offset8, offset8 + 8).map(c => ({
  charger_id: c.charger_id,
  charger_kw: c.charger_kw,
}));

const trips  = allTrips.slice(offset8, offset8 + 8);
const prices = allPrices;

const currentTimestep = $('Timestep').first().json.targetTimestep;
const realtimeState = $('Code in JavaScript').all()
  .flatMap(i => i.json.buses)
  .filter(bus => bus.current_timestep === currentTimestep)
  .map(bus => ({
    bus_id:             bus.bus_id,
    current_timestep:   bus.current_timestep,
