if (!buses.length)         throw new Error(`buses empty — allBuses has ${allBuses.length} rows, offset=${offset8}`);
if (!chargers.length)      throw new Error(`chargers empty`);
if (!prices.length)        throw new Error(`prices empty`);
if (!realtimeState.length) throw new Error(`realtimeState empty`);

return [{
  json: {
    input: {
      buses,
      chargers,
      trip_time:          trips,
      energy_consumption: trips,
      prices,
      realtime_state:     realtimeState,
