      chargers: allChargers,
      trips:    allTrips,
      prices:   allPrices,
    }
  }
}];

const realtimePlan = $('Generate Summary').item.json.realtime_plan;
const currentTimestep = $('Timestep').first().json.targetTimestep;
const triggerType = $('Trigger Agent').last().json.output.trigger_type;
const extractResult = $('Extract Result').last().json;

return [{
  json: {
    realtime_plan: realtimePlan.filter(row => row.timestep >= currentTimestep).map(row => {
      if (row.timestep === currentTimestep) {
        return {
          ...row,
          buy_multipliers:  JSON.stringify(extractResult.buy_multipliers),
