          intraday_prices:  JSON.stringify(extractResult.intraday_prices ?? []),
          reoptimized:      true,
          trigger_type:     triggerType,
        };
      }
      return {
        timestep:  row.timestep,
        w_buy:     row.w_buy,
        w_sell:    row.w_sell,
        bus_1_kwh: row.bus_1_kwh,
        bus_2_kwh: row.bus_2_kwh,
        bus_3_kwh: row.bus_3_kwh,
        bus_4_kwh: row.bus_4_kwh,
        bus_5_kwh: row.bus_5_kwh,
        bus_6_kwh: row.bus_6_kwh,
        bus_7_kwh: row.bus_7_kwh,
        bus_8_kwh: row.bus_8_kwh,
      };
    })
  }
}];

