const allPriceRows = $('Load Prices').all().map(i => i.json);
let prices = allPriceRows.map(r => ({
  timestep:    r.timestep,
  spot_market: r.spot_market,
}));

// Get ALL active scenarios from Filter2, keep only price ones
const scenarios = $('Filter2').all().map(i => i.json)
  .filter(s => s.scenario_id && s.scenario_id.startsWith('price_'));

// Compose multipliers across all active price scenarios
for (const scenario of scenarios) {
  const multiplier = 1 + (scenario.disturbance_sign * scenario.scenario_level / 100);
  const start = scenario.start_timestep;
  const end   = scenario.end_timestep;
  prices = prices.map(p => {
    if (p.timestep >= start && p.timestep <= end) {
      return { ...p, spot_market: p.spot_market * multiplier };
    }
    return p;
  });
}

return [{ json: { prices } }];

const input             = $('Assembler node').first().json.input;
const realtimePlanItems = $('Load day_ahead_plan').all().map(i => i.json);
const currentTimestep   = $('Timestep').first().json.targetTimestep;

// Get ALL active energy scenarios from Filter2
const scenarios = $('Filter2').all().map(i => i.json)
  .filter(s => s.scenario_id && s.scenario_id.startsWith('energy_'));

let energy_consumption = input.energy_consumption;
const disturbed_delta   = {};
const undisturbed_delta = {};

// Initialize deltas from raw DA plan (undisturbed baseline)
const currentRow  = realtimePlanItems.find(r => r.timestep === currentTimestep);
const previousRow = realtimePlanItems.find(r => r.timestep === currentTimestep - 1);

for (let b = 1; b <= 8; b++) {
  const key     = `bus_${b}_kwh`;
  const currKwh = currentRow?.[key]  ?? null;
  const prevKwh = previousRow?.[key] ?? null;
  const delta   = currKwh !== null && prevKwh !== null ? currKwh - prevKwh : null;
  undisturbed_delta[key] = delta;
  disturbed_delta[key]   = delta; // will be overwritten per scenario below
}

// Compose multipliers across all active energy scenarios
let composedMultipliers = {}; // per bus
for (let b = 1; b <= 8; b++) composedMultipliers[`bus_${b}_kwh`] = 1.0;

for (const scenario of scenarios) {
  if (typeof scenario.target_bus_id === 'string') {
    scenario.target_bus_id = JSON.parse(scenario.target_bus_id);
  }
  const targetBusIds = Array.isArray(scenario.target_bus_id)
    ? scenario.target_bus_id
    : [scenario.target_bus_id];

  const reoptAfterStart = realtimePlanItems.find(
    r => r.reoptimized === true && r.timestep >= scenario.start_timestep
  );
  const reoptAfterEnd = realtimePlanItems.find(
    r => r.reoptimized === true && r.timestep >= scenario.end_timestep
  );

  const shouldApply  = currentTimestep >= scenario.start_timestep && !reoptAfterStart;
  const shouldRemove = currentTimestep >= scenario.end_timestep && !!reoptAfterStart && !reoptAfterEnd;

  if (!shouldApply && !shouldRemove) continue;

  const baseMultiplier = 1 + (scenario.disturbance_sign * scenario.scenario_level / 100);
  const multiplier     = shouldRemove ? 1 / baseMultiplier : baseMultiplier;

  for (let b = 1; b <= 8; b++) {
    const isTarget = scenario.target_scope === 'global' || targetBusIds.includes(b);
    if (isTarget) {
      composedMultipliers[`bus_${b}_kwh`] *= multiplier;
    }
  }
}

// Apply composed multipliers to energy_consumption
energy_consumption = energy_consumption.map(e => {
  const key = `bus_${e.bus_id}_kwh`;
  const m   = composedMultipliers[key] ?? 1.0;
  if (m !== 1.0) {
    return { ...e, energy_kwhkm: e.energy_kwhkm * m };
  }
  return e;
});

// Apply composed multipliers to disturbed_delta (negative deltas = consumption)
for (let b = 1; b <= 8; b++) {
  const key   = `bus_${b}_kwh`;
  const delta = undisturbed_delta[key];
  const m     = composedMultipliers[key] ?? 1.0;
  if (m !== 1.0 && delta !== null && delta < 0) {
    disturbed_delta[key] = parseFloat((delta * m).toFixed(4));
  }
}

return [{ json: {
  ...input,
  energy_consumption,
  disturbed_delta,
  undisturbed_delta,
  current_timestep: currentTimestep,
} }];

// Force accept if rerun cap reached
const rerunCount = $('Check Rerun Cap').isExecuted 
  ? $('Check Rerun Cap').last().json.rerun_count ?? 0 : 0;
const isMock = $('Extract Result').last().json.is_mock === true;

if (rerunCount >= 3) {
  return [{ json: { skip_evaluator: true, accept: true } }];
}

return [{ json: { skip_evaluator: false } }];

const rows = $input.all().map(i => i.json);
const currentTimestep = $('Timestep').first().json.targetTimestep;

// Get disturbed and undisturbed deltas from Energy Disturbance node
let disturbedDelta   = {};
let undisturbedDelta = {};
try {
  const energyDistNode = $('Energy Disturbance node').first().json;
  disturbedDelta   = energyDistNode.disturbed_delta   || {};
  undisturbedDelta = energyDistNode.undisturbed_delta || {};
} catch(e) {}

const filteredRows = rows.filter(r => r.timestep <= currentTimestep && r.timestep > 0);

return filteredRows.map(row => ({
  json: {
    timestep: row.timestep,
    buses: [1,2,3,4,5,6,7,8].map(b => {
      const key       = `bus_${b}_kwh`;
      let observedKwh = row[key];

      // At current timestep only — adjust observed SOC to reflect
      // actual disturbed energy consumption rather than DA plan value
      if (row.timestep === currentTimestep) {
        const dDelta = disturbedDelta[key];
        const uDelta = undisturbedDelta[key];

        if (
          dDelta !== null && dDelta !== undefined &&
          uDelta !== null && uDelta !== undefined &&
          uDelta !== dDelta // only adjust if disturbance actually changed something
        ) {
          // plan_value = prevKwh + undisturbed_delta
          // actual     = prevKwh + disturbed_delta
          // therefore: actual = plan_value - undisturbed_delta + disturbed_delta
          observedKwh = observedKwh - uDelta + dDelta;
          observedKwh = Math.min(365, Math.max(73, observedKwh));
        }
      }

      return {
        bus_id:             b,
        current_timestep:   row.timestep,
        current_soc:        null,
        current_energy_kwh: parseFloat(observedKwh.toFixed(4)),
        operation_status:   'idle',
        delay_minutes:      0,
      };
    })
  }
}));

const currentTimestep = $('Build LLM context').last().json.context.timestep;
const context         = $('Build LLM context').last().json.context;
const scenarios       = $('Filter2').all().map(i => i.json);

const results = [];

// ── Price ──────────────────────────────────────────────────────────────────
const priceScenarios = scenarios.filter(s => s.scenario_id?.startsWith('price_'));

// Compose price multiplier across all active price scenarios
let priceMultiplier = 1;
for (const s of priceScenarios) {
  const active = currentTimestep >= parseInt(s.start_timestep)
              && currentTimestep <= parseInt(s.end_timestep);
  if (active) {
    priceMultiplier *= 1 + (s.disturbance_sign * s.scenario_level / 100);
  }
}

const basePriceRows = $('Load Prices').all().map(i => i.json);
basePriceRows
  .filter(r => r.timestep >= currentTimestep)
  .forEach(r => {
    results.push({
      json: {
        update_type: 'price',
        timestep:    r.timestep,
        spot_market: parseFloat((r.spot_market * priceMultiplier).toFixed(10)),
        row_number:  r.row_number,
      }
    });
  });

// ── Energy ─────────────────────────────────────────────────────────────────
const energyScenarios = scenarios.filter(s => s.scenario_id?.startsWith('energy_'));

const E_MIN = 73;
const E_MAX = 365;

const dayAheadPlanRows = $('Load day_ahead_plan').all()
  .map(i => i.json)
  .sort((a, b) => a.timestep - b.timestep);

// Build composed energy multiplier per bus across all active energy scenarios
const energyMultipliers = {};
for (let b = 1; b <= 8; b++) energyMultipliers[b] = 1;

for (const s of energyScenarios) {
  if (typeof s.target_bus_id === 'string') {
    try { s.target_bus_id = JSON.parse(s.target_bus_id); } catch(e) {}
  }
  const targetBusIds = Array.isArray(s.target_bus_id)
    ? s.target_bus_id.map(Number)
    : [Number(s.target_bus_id)];

  const active = currentTimestep >= parseInt(s.start_timestep)
              && currentTimestep <= parseInt(s.end_timestep);
  if (!active) continue;

  const m = 1 + (s.disturbance_sign * s.scenario_level / 100);
  for (let b = 1; b <= 8; b++) {
    if (s.target_scope === 'global' || targetBusIds.includes(b)) {
      energyMultipliers[b] *= m;
    }
  }
}

const disturbedKwh = {};
for (let b = 1; b <= 8; b++) {
  const dev = (context.deviations || []).find(d => d.bus_id === b);
  if (dev && dev.current_energy_kwh != null) {
    disturbedKwh[b] = dev.current_energy_kwh;
  } else {
    const currentRow = dayAheadPlanRows.find(r => r.timestep === currentTimestep);
    disturbedKwh[b] = currentRow ? currentRow[`bus_${b}_kwh`] : null;
  }
}

const futureRows = dayAheadPlanRows.filter(r => r.timestep >= currentTimestep);

futureRows.forEach((r, idx) => {
  const row = { update_type: 'energy', timestep: r.timestep, row_number: r.row_number };

  for (let b = 1; b <= 8; b++) {
    const key = `bus_${b}_kwh`;
    if (idx === 0) {
      row[key] = parseFloat(disturbedKwh[b].toFixed(4));
    } else {
      const prevRow    = futureRows[idx - 1];
      const daDelta    = r[key] - prevRow[key];
      const m          = energyMultipliers[b];
      const distDelta  = (m !== 1 && daDelta < 0) ? daDelta * m : daDelta;
      const newKwh     = Math.min(E_MAX, Math.max(E_MIN, disturbedKwh[b] + distDelta));
      disturbedKwh[b]  = newKwh;
      row[key]         = parseFloat(newKwh.toFixed(4));
    }
  }
  results.push({ json: row });
});


return results;

