const input             = $('Assembler node').first().json.input;
const currentTimestep   = $('Timestep').first().json.targetTimestep;
const realtimePlanItems = $('Load day_ahead_plan').all().map(i => i.json);

// Get ALL active delay scenarios
const scenarios = $('Filter2').all().map(i => i.json)
  .filter(s => s.scenario_family === 'delay_minutes');

function addMinutes(timeStr, minutes) {
  const [h, m] = timeStr.split(':').map(Number);
  const total  = h * 60 + m + minutes;
  const norm   = ((total % 1440) + 1440) % 1440;
  return `${String(Math.floor(norm / 60)).padStart(2,'0')}:${String(norm % 60).padStart(2,'0')}`;
}

function timeToTimestep(timeStr) {
  const [h, m] = timeStr.split(':').map(Number);
  return Math.floor((h * 60 + m) / 30) + 1;
}

let trip_time  = input.trip_time;
const delay_info = {};
for (let b = 1; b <= 8; b++) delay_info[b] = 0;
let anyBusAtEndWindow = false;

for (const scenario of scenarios) {
  if (typeof scenario.target_bus_id === 'string') {
    try { scenario.target_bus_id = JSON.parse(scenario.target_bus_id); } catch(e) {}
  }
  const targetBusIds = Array.isArray(scenario.target_bus_id)
    ? scenario.target_bus_id
    : [scenario.target_bus_id];

  const delayMinutes = scenario.disturbance_sign * scenario.scenario_level;

  const reoptAfterStart = realtimePlanItems.find(
    r => r.reoptimized === true && r.timestep >= scenario.start_timestep
  );
  const reoptAfterEnd = realtimePlanItems.find(
    r => r.reoptimized === true && r.timestep >= scenario.end_timestep
  );
  const disturbanceApplied = !!reoptAfterStart;
  const disturbanceRemoved = !!reoptAfterEnd;

  const shouldApply = currentTimestep >= scenario.start_timestep && !disturbanceApplied;

  if (shouldApply) {
    trip_time = trip_time.map(t => {
      if (scenario.target_scope === 'global' || targetBusIds.includes(t.bus_id)) {
        const tripStartTimestep  = timeToTimestep(t.time_begin);
        const tripAlreadyStarted = currentTimestep >= tripStartTimestep;
        return {
          ...t,
          time_begin: tripAlreadyStarted ? t.time_begin : addMinutes(t.time_begin, delayMinutes),
          time_end:   addMinutes(t.time_end, delayMinutes),
        };
      }
      return t;
    });
  }

  for (let b = 1; b <= 8; b++) {
    const isTarget = scenario.target_scope === 'global' || targetBusIds.includes(b);
    const isActive = currentTimestep >= scenario.start_timestep && isTarget;
    const atEndWindow = isActive && currentTimestep >= scenario.end_timestep && !disturbanceRemoved;

    if (atEndWindow) anyBusAtEndWindow = true;

    delay_info[b] += !isActive           ? 0
      : !disturbanceApplied              ? delayMinutes
      : atEndWindow                      ? -delayMinutes
      : 0;
  }
}

return [{ json: {
  ...input,
  trip_time,
  delay_info,
  delay_removal_active: anyBusAtEndWindow,
  current_timestep: currentTimestep,
} }];

